function solve(nums: number[], queries: number[][]): number {
    const MOD = 10**9 + 7;
    const n = nums.length;

    // For each position, track how many times it is multiplied by a value
    // We use a frequency array to count the number of multiplications
    const freq = new Array(n).fill(0);

    for (const [li, ri, ki, vi] of queries) {
        let idx = li;
        while (idx <= ri) {
            freq[idx] += 1;
            idx += ki;
        }
    }

    // Apply the multiplications
    for (let i = 0; i < n; i++) {
        nums[i] = (nums[i] ** freq[i]) % MOD;
    }

    // Compute the XOR of all elements
    let xorResult = 0;
    for (const num of nums) {
        xorResult ^= num;
    }

    return xorResult;
}
